import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 鍛造系統深入指南：從學徒到神匠","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/smithing-guide.md","filePath":"bannerlord/smithing-guide.md"}'),l={name:"bannerlord/smithing-guide.md"};function h(i,t,o,n,s,b){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="騎砍2-鍛造系統深入指南-從學徒到神匠" tabindex="-1">騎砍2 | 鍛造系統深入指南：從學徒到神匠 <a class="header-anchor" href="#騎砍2-鍛造系統深入指南-從學徒到神匠" aria-label="Permalink to &quot;騎砍2 | 鍛造系統深入指南：從學徒到神匠&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>鍛造是騎砍2最暴利的系統——一把好劍可以賣到幾萬金。但新手最大的障礙是：不知道怎麼練、不知道哪些配件值錢、不知道材料去哪找。</p><p>這篇一次講清楚。</p><hr><h2 id="一、鍛造基礎" tabindex="-1">一、鍛造基礎 <a class="header-anchor" href="#一、鍛造基礎" aria-label="Permalink to &quot;一、鍛造基礎&quot;">​</a></h2><h3 id="_1-1-需要的東西" tabindex="-1">1.1 需要的東西 <a class="header-anchor" href="#_1-1-需要的東西" aria-label="Permalink to &quot;1.1 需要的東西&quot;">​</a></h3><table tabindex="0"><thead><tr><th>材料</th><th>來源</th><th>備註</th></tr></thead><tbody><tr><td><strong>硬木</strong></td><td>巴坦尼亞村莊買</td><td>圍繞 <strong>Marunath、Seonon、Dunglanys</strong> 的村：Glenlithrig、Tor Leiad、Mag Arba、Ebbseth、Tor Melina，硬木 15-30 金/個，一次買 100 個起</td></tr><tr><td><strong>鐵礦/粗鐵</strong></td><td>熔煉武器獲得</td><td>不要買！熔煉更划算</td></tr><tr><td><strong>鍛造技能</strong></td><td>耐力屬性影響</td><td>同伴可以幫忙（找有鍛造技能的同伴當鐵匠）</td></tr></tbody></table><h3 id="_1-2-熔煉-鍛造" tabindex="-1">1.2 熔煉 &gt; 鍛造 <a class="header-anchor" href="#_1-2-熔煉-鍛造" aria-label="Permalink to &quot;1.2 熔煉 &gt; 鍛造&quot;">​</a></h3><p>練鍛造最快的方式是<strong>熔煉武器</strong>，不是鍛造武器。</p><ul><li>所有打仗撿到的武器 → 拿去熔煉</li><li>熔煉解鎖配件配方 + 獲得大量經驗 + 獲得材料</li><li>一把熔掉，材料拿來鍛造更好的武器</li></ul><hr><h2 id="二、從零開始練鍛造" tabindex="-1">二、從零開始練鍛造 <a class="header-anchor" href="#二、從零開始練鍛造" aria-label="Permalink to &quot;二、從零開始練鍛造&quot;">​</a></h2><h3 id="階段-1-熔煉期-技能-0-50" tabindex="-1">階段 1：熔煉期（技能 0-50） <a class="header-anchor" href="#階段-1-熔煉期-技能-0-50" aria-label="Permalink to &quot;階段 1：熔煉期（技能 0-50）&quot;">​</a></h3><ol><li>買 100 個硬木</li><li>打仗撿武器全部熔掉</li><li>只做 T1-T2 武器練手</li><li>點出 perk：熟練鐵匠（10級）→ 鋼鐵提煉師（25級）</li></ol><h3 id="階段-2-賺錢期-技能-50-150" tabindex="-1">階段 2：賺錢期（技能 50-150） <a class="header-anchor" href="#階段-2-賺錢期-技能-50-150" aria-label="Permalink to &quot;階段 2：賺錢期（技能 50-150）&quot;">​</a></h3><ol><li>開始做 T4-T5 雙手劍</li><li>材料成本約 500 金 → 賣價 5000-15000 金</li><li>點出 perk：精製鋼（50級）→ 大師鐵匠（75級）</li></ol><h3 id="階段-3-暴富期-技能-150" tabindex="-1">階段 3：暴富期（技能 150+） <a class="header-anchor" href="#階段-3-暴富期-技能-150" aria-label="Permalink to &quot;階段 3：暴富期（技能 150+）&quot;">​</a></h3><ol><li>T5-T6 武器隨便做</li><li>頂級雙手劍賣價 20000-50000 金</li><li>從此錢不再是問題</li></ol><hr><h2 id="三、最賺錢配方" tabindex="-1">三、最賺錢配方 <a class="header-anchor" href="#三、最賺錢配方" aria-label="Permalink to &quot;三、最賺錢配方&quot;">​</a></h2><h3 id="雙手劍-目前最賺" tabindex="-1">雙手劍（目前最賺） <a class="header-anchor" href="#雙手劍-目前最賺" aria-label="Permalink to &quot;雙手劍（目前最賺）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>部位</th><th>推薦配件</th><th style="text-align:center;">等級</th></tr></thead><tbody><tr><td>刀刃</td><td>帝國刀刃 / 長戰劍刃</td><td style="text-align:center;">T5</td></tr><tr><td>護手</td><td>裝飾護手 / 皇家護手</td><td style="text-align:center;">T4</td></tr><tr><td>握柄</td><td>皮革長握柄 / 金紋握柄</td><td style="text-align:center;">T4</td></tr><tr><td>配重</td><td>鋼配重塊 / 金配重</td><td style="text-align:center;">T3</td></tr></tbody></table><blockquote><p>關鍵是刀刃等級——T5 刀刃做的武器價值是 T3 的 3-5 倍。</p></blockquote><h3 id="長桿武器-第二賺" tabindex="-1">長桿武器（第二賺） <a class="header-anchor" href="#長桿武器-第二賺" aria-label="Permalink to &quot;長桿武器（第二賺）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>部位</th><th>推薦配件</th></tr></thead><tbody><tr><td>長桿頭</td><td>帝國長矛頭 T5</td></tr><tr><td>長桿身</td><td>硬木長桿 T4</td></tr></tbody></table><hr><h2 id="四、材料取得" tabindex="-1">四、材料取得 <a class="header-anchor" href="#四、材料取得" aria-label="Permalink to &quot;四、材料取得&quot;">​</a></h2><table tabindex="0"><thead><tr><th>材料</th><th>來源</th><th>備註</th></tr></thead><tbody><tr><td>鐵礦</td><td>熔煉低階武器</td><td>最普遍</td></tr><tr><td>鋼鐵</td><td>熔煉中階武器 / 精煉鐵礦</td><td>技能 25 解鎖精煉</td></tr><tr><td>優質鋼</td><td>熔煉高階武器</td><td>稀有，省著用</td></tr><tr><td>瑟雷因鋼</td><td>熔煉特定武器 / 精煉</td><td>最稀有</td></tr></tbody></table><blockquote><p>💡 <strong>不要買材料！</strong> 熔煉武器獲得的材料遠比直接買划算。</p></blockquote><hr><h2 id="五、常見問題" tabindex="-1">五、常見問題 <a class="header-anchor" href="#五、常見問題" aria-label="Permalink to &quot;五、常見問題&quot;">​</a></h2><h3 id="q-為什麼我做的武器賣不了高價" tabindex="-1">Q：為什麼我做的武器賣不了高價？ <a class="header-anchor" href="#q-為什麼我做的武器賣不了高價" aria-label="Permalink to &quot;Q：為什麼我做的武器賣不了高價？&quot;">​</a></h3><p>檢查：刀刃等級夠高嗎？配件全是你能做的最高等級嗎？武器傷害值越高賣越貴。</p><h3 id="q-配件配方怎麼解鎖" tabindex="-1">Q：配件配方怎麼解鎖？ <a class="header-anchor" href="#q-配件配方怎麼解鎖" aria-label="Permalink to &quot;Q：配件配方怎麼解鎖？&quot;">​</a></h3><p>熔煉武器會隨機解鎖該武器使用的配件配方。想解鎖更多配方 = 熔更多不同種類的武器。</p><h3 id="q-同伴能幫我做嗎" tabindex="-1">Q：同伴能幫我做嗎？ <a class="header-anchor" href="#q-同伴能幫我做嗎" aria-label="Permalink to &quot;Q：同伴能幫我做嗎？&quot;">​</a></h3><p>可以。找有鍛造技能的同伴，設置為鐵匠，他就會在城鎮幫你熔煉和鍛造。</p><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./money-making.html">騎砍2 | 賺錢密技</a></li><li><a href="./trade-routes.html">騎砍2 | 終極跑商路線圖</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',47)])])}const q=a(l,[["render",h]]);export{u as __pageData,q as default};
